(9, '🚨 ALERTA: Posible Manifestación y Protesta Vecinal en El Talar', $$<!-- 56 700-->\n\n<!-- BANNER SUPERIOR CON LOGO Y FONDO INSTITUCIONAL -->\n<div style="background: linear-gradient(90deg, #d32f2f 60%, #f9f9f9 100%); padding: 24px 0 12px 0; border-radius: 0 0 32px 32px; box-shadow: 0 4px 24px #0002; position:relative; overflow:hidden;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF Noticias extendido" style="width:340px;max-width:90vw;display:block;margin:0 auto 8px auto;filter:drop-shadow(0 2px 8px #0005);">\n  <div style="position:absolute;right:24px;bottom:-10px;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi mascota" style="width:90px;max-width:20vw;">\n  </div>\n</div>\n\n<!-- TITULO Y SLOGAN -->\n<div style="text-align:center;margin-top:18px;">\n  <h1 style="color:#d32f2f;font-size:2.2em;margin-bottom:0;">🚨 ALERTA: Posible Manifestación y Protesta Vecinal en El Talar</h1>\n  <h2 style="color:#222;font-size:1.3em;font-style:italic;margin-top:0;">¿Reclamos, denuncias y tensión frente a un local de la zona?</h2>\n  <p style="color:#555;font-size:1.1em;margin:0 0 8px 0;"><strong>El Talar, Buenos Aires – Sábado 11 de Julio 2025</strong></p>\n  <div style="display:inline-block;background:#fff3f2;border-radius:8px;padding:6px 18px;margin-bottom:8px;border:1.5px solid #d32f2f;font-size:1.1em;color:#d32f2f;font-style:italic;box-shadow:0 2px 8px #d32f2f22;">"La realidad a un click de distancia"</div>\n</div>\n\n<!-- PORTADA INSTITUCIONAL -->\n<a href="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i52cb1a4d6ae01039/version/1752210338/image.png" target="_blank">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i52cb1a4d6ae01039/version/1752210338/image.png" alt="Esquina El Talar" style="width:100%;max-width:900px;border-radius:16px;margin:24px auto 18px auto;display:block;box-shadow:0 4px 24px #0001;cursor:pointer;">\n</a>\n\n<!-- PRESENTACION Y BLOQUE DESTACADO -->\n<div style="max-width:800px;margin:0 auto 18px auto;">\n  <p style="font-size:1.25em;line-height:1.7;">\n    <strong>Vecinos de El Talar</strong> han convocado a una <span style="color:#d32f2f;font-weight:bold;">posible marcha y escrache</span> frente a un conocido local de la zona, ubicado en Av. Hipólito Yrigoyen y Pasteur, en reclamo por <span style="color:#d32f2f;font-weight:bold;">supuestos sueldos impagos, maltrato laboral y venta de productos vencidos</span>. Las denuncias, que circulan en redes y grupos barriales, señalan situaciones de abuso y condiciones laborales precarias. <br><br>\n    <span style="background:#fff3f2;padding:2px 8px;border-radius:6px;color:#d32f2f;font-weight:bold;">¡La indignación crece y la comunidad se moviliza!</span>\n  </p>\n  <blockquote style="border-left:5px solid #d32f2f;padding-left:16px;color:#444;background:#f9f9f9;border-radius:8px;font-size:1.18em;margin:18px 0;box-shadow:0 2px 8px #d32f2f11;">\n    <em>"No vamos a quedarnos callados. Exigimos respuestas y respeto. ¡Paguen lo que deben y mejoren el trato!"</em> – Testimonio anónimo compartido en redes.\n  </blockquote>\n</div>\n\n<!-- BLOQUE: ¿QUÉ PASA EN EL LOCAL? -->\n<div style="display:flex;align-items:center;gap:18px;max-width:900px;margin:0 auto 24px auto;background:#f7f7f7;border-radius:12px;padding:18px 18px 12px 18px;box-shadow:0 2px 12px #d32f2f11;">\n  <a href="https://images.rappi.com.ar/restaurants_logo/costumbres-argentinas-logo1-1567622799197.png" target="_blank">\n    <img src="https://images.rappi.com.ar/restaurants_logo/costumbres-argentinas-logo1-1567622799197.png" alt="Logo Costumbres Argentinas" style="width:80px;min-width:60px;max-width:20vw;cursor:pointer;">\n  </a>\n  <div style="flex:1;">\n    <h3 style="color:#d32f2f;margin:0 0 6px 0;font-size:1.25em;">¿Por qué la protesta?</h3>\n    <ul style="margin:0 0 0 18px;padding:0;font-size:1.15em;line-height:1.7;color:#333;">\n      <li>Supuestos sueldos impagos y trabajo en negro.</li>\n      <li>Denuncias de maltrato laboral y falta de pago de feriados y aguinaldos.</li>\n      <li>Acusaciones sobre venta de productos vencidos y condiciones inseguras.</li>\n      <li>Quejas por escapes de gas y conexiones eléctricas irregulares.</li>\n      <li>Reclamos extendidos a aplicaciones de delivery y redes sociales.</li>\n    </ul>\n  </div>\n</div>\n\n<!-- BLOQUE DE IMAGEN Y REDES -->\n<div style="background:linear-gradient(90deg,#f7f7f7 60%,#e3f2fd 100%);border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;display:flex;align-items:center;gap:18px;">\n  <a href="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i62b5c08f3a188f7e/version/1752209731/image.png" target="_blank">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i62b5c08f3a188f7e/version/1752209731/image.png" alt="Queja en app" style="width:120px;max-width:30vw;cursor:pointer;">\n  </a>\n  <div style="flex:1;">\n    <h3 style="color:#d32f2f;margin:0 0 6px 0;font-size:1.25em;">Las denuncias también llegan por apps y redes</h3>\n    <p style="margin:0;font-size:1.15em;">Vecinos y ex empleados comparten capturas y testimonios en redes sociales y aplicaciones de delivery, ampliando el reclamo más allá del local físico.</p>\n  </div>\n</div>\n\n<!-- LLLAMADO A PARTICIPACION Y BOTONES -->\n<div style="background:#fff3f2;border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;">\n  <h3 style="color:#d32f2f;font-size:1.25em;">📝 ¿Sos vecino de El Talar o Zona Norte?</h3>\n  <p style="font-size:1.15em;">¿Tenés información, reclamo o testimonio sobre este caso? ¿Querés sumar tu voz o compartir tu experiencia? <strong>Contactanos y participá:</strong></p>\n  <div style="display:flex;flex-wrap:wrap;gap:12px;margin:12px 0 0 0;">\n    <a href="https://wa.me/5491137910547?text=Hola%20ZNSF%20Noticias%2C%20quiero%20enviar%20una%20noticia%20o%20consulta%20(sobre%20protesta%20El%20Talar)" target="_blank" style="display:flex;align-items:center;gap:8px;background:#25d366;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #25d36633;transition:transform .1s;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i54f0f9e8bb7b09aa/version/1752083005/image.png" alt="WhatsApp" style="width:24px;">\n      WhatsApp ZNSF Noticias\n    </a>\n    <a href="https://whatsapp.com/channel/0029Vb70uu90G0XdCw51eg0u" target="_blank" style="display:flex;align-items:center;gap:8px;background:#d32f2f;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #d32f2f33;transition:transform .1s;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i3fcaf367916af1a8/version/1752084059/image.png" alt="Canal WhatsApp" style="width:24px;">\n      Canal WhatsApp\n    </a>\n    <a href="https://chat.whatsapp.com/EjvvlEb48y641BeACmlLlJ" target="_blank" style="display:flex;align-items:center;gap:8px;background:#222;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #2222;transition:transform .1s;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i94e3b69c51d5d643/version/1752084071/image.png" alt="Grupo Vecinal" style="width:24px;">\n      Grupo Vecinal\n    </a>\n    <span style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;font-size:1.08em;border:1.5px solid #d32f2f;user-select:all;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i9267260f4dd5540d/version/1752084082/image.png" alt="Gmail" style="width:24px;">\n      znsfnoticias@gmail.com\n    </span>\n  </div>\n</div>\n\n<!-- BLOQUE: SUMATE AL STAFF -->\n<div style="background:linear-gradient(90deg,#fff3f2 60%,#f7f7f7 100%);border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;display:flex;align-items:center;gap:18px;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo extendido ZNSF" style="width:90px;max-width:20vw;">\n  <div style="flex:1;">\n    <h3 style="color:#d32f2f;margin:0 0 6px 0;font-size:1.25em;">¿Querés sumarte al staff?</h3>\n    <p style="margin:0;font-size:1.15em;">Buscamos colaboradores, cronistas, fotógrafos, editores y vecinos con ganas de aportar a la comunidad. ¡Sumate y hacé crecer el periodismo local!</p>\n    <a href="https://wa.me/5491137910547?text=Hola%20ZNSF%20Noticias%2C%20quiero%20sumarme%20al%20staff%20(desde%20noticia%20protesta%20El%20Talar)" style="display:inline-block;margin-top:8px;background:#d32f2f;color:#fff;font-weight:bold;padding:8px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #d32f2f33;">Postularme por WhatsApp</a>\n    <span style="display:inline-block;margin-top:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:8px 18px;border-radius:8px;font-size:1.08em;border:1.5px solid #d32f2f;user-select:all;">znsfnoticias@gmail.com</span>\n  </div>\n</div>\n\n<!-- BLOQUE REDES SOCIALES Y CONTACTO -->\n<div style="max-width:900px;margin:0 auto 24px auto;background:#f7f7f7;border-radius:14px;padding:18px 18px 12px 18px;box-shadow:0 2px 12px #d32f2f11;">\n  <h3 style="color:#d32f2f;margin-bottom:10px;font-size:1.25em;">Seguinos y participá en nuestras redes</h3>\n  <div style="display:flex;flex-wrap:wrap;gap:16px;align-items:center;justify-content:center;">\n    <a href="https://www.instagram.com/znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/id31bfdb8887a4101/version/1752082976/image.png" alt="Instagram" style="width:24px;"> Instagram\n    </a>\n    <a href="https://www.youtube.com/@ZNSFNoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i2c42051c382a77df/version/1752083038/image.png" alt="YouTube" style="width:24px;"> YouTube\n    </a>\n    <a href="https://x.com/znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/idd2b980f4adc5de5/version/1752083026/image.png" alt="Twitter/X" style="width:24px;"> Twitter/X\n    </a>\n    <a href="https://www.tiktok.com/@znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/iafacb98ca891b2da/version/1752082994/image.png" alt="TikTok" style="width:24px;"> TikTok\n    </a>\n    <a href="https://www.facebook.com/znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i924b6a16ba5143d0/version/1752082966/image.png" alt="Facebook" style="width:24px;"> Facebook\n    </a>\n  </div>\n</div>\n\n<!-- FOOTER INSTITUCIONAL -->\n<hr style="margin:32px 0 12px 0;border:0;border-top:2px solid #d32f2f33;">\n<div style="text-align:center;font-size:17px;color:#555;max-width:900px;margin:0 auto 18px auto;">\n  <strong>ZNSF Noticias</strong> • Medio Digital de Zona Norte<br>\n  <span style="color:#d32f2f;">🌍</span> <a href="https://znsfnoticias.jimdofree.com/" target="_blank" style="color:#d32f2f;font-weight:bold;">znsfnoticias.jimdofree.com</a>  |\n  <span style="color:#25d366;">📢</span> <a href="https://whatsapp.com/channel/0029Vb70uu90G0XdCw51eg0u" target="_blank" style="color:#25d366;font-weight:bold;">Canal en WhatsApp</a>  |\n  <span style="color:#222;">👥</span> <a href="https://chat.whatsapp.com/EjvvlEb48y641BeACmlLlJ" target="_blank" style="color:#222;font-weight:bold;">Grupo Vecinal</a><br>\n  Seguinos en redes: <span style="color:#d32f2f;">@znsfnoticias</span>\n</div>\n\n<!-- MICROANIMACION: EFECTO DE ENTRADA PARA EL BANNER SUPERIOR -->\n<script>\n  window.addEventListener('DOMContentLoaded',()=>{\n    // Animación de entrada para el banner superior\n    const banner=document.querySelector('div[style*="linear-gradient"]');\n    if(banner){\n      banner.style.transform='translateY(-40px)';\n      banner.style.opacity='0';\n      setTimeout(()=>{\n        banner.style.transition='all .7s cubic-bezier(.7,0,.3,1)';\n        banner.style.transform='translateY(0)';\n        banner.style.opacity='1';\n      },200);\n    }\n  });\n</script>\n\n<!-- BLOQUE FINAL: COBERTURA ZNSF -->\n<div style="background:#fff3f2;border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:32px auto 24px auto;">\n  <h3 style="color:#d32f2f;font-size:1.25em;">🔎 Cobertura ZNSF Noticias</h3>\n  <p style="font-size:1.15em;">El equipo de <strong>ZNSF Noticias</strong> se presentará en el lugar de la protesta para indagar sobre las acusaciones y escuchar todas las voces. <br> <span style="color:#d32f2f;font-weight:bold;">Recordamos que todas las declaraciones y denuncias aquí expuestas son <u>supuestas</u> y no se publican nombres propios para preservar la seguridad institucional y la privacidad de los involucrados.</span></p>\n</div>$$, '2025-07-11', 'Denuncias y reclamos vecinales', 'https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i52cb1a4d6ae01039/version/1752210338/image.png', NULL, '2025-07-11 05:41:04.933013+00', 60, 764, 21, 22, NULL, '2025-07-11 05:41:04.933013+00', NULL),
(8, 'Bienvenidos a ZNSF Noticias: la voz de San Fernando', $$<!-- 72 455 BANNER SUPERIOR CON LOGO Y FONDO INSTITUCIONAL -->\n<div style="background: linear-gradient(90deg, #d32f2f 60%, #f9f9f9 100%); padding: 24px 0 12px 0; border-radius: 0 0 32px 32px; box-shadow: 0 4px 24px #0002; position:relative; overflow:hidden;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF Noticias extendido" style="width:340px;max-width:90vw;display:block;margin:0 auto 8px auto;filter:drop-shadow(0 2px 8px #0005);">\n  <div style="position:absolute;right:24px;bottom:-10px;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi mascota" style="width:90px;max-width:20vw;">\n  </div>\n</div>\n\n<!-- TITULO Y SLOGAN -->\n<div style="text-align:center;margin-top:18px;">\n  <h1 style="color:#d32f2f;font-size:2.2em;margin-bottom:0;">Bienvenidos a ZNSF Noticias</h1>\n  <h2 style="color:#222;font-size:1.3em;font-style:italic;margin-top:0;">La voz de los vecinos de San Fernando</h2>\n  <p style="color:#555;font-size:1.1em;margin:0 0 8px 0;"><strong>San Fernando, Buenos Aires – Julio 2025</strong></p>\n  <div style="display:inline-block;background:#fff3f2;border-radius:8px;padding:6px 18px;margin-bottom:8px;border:1.5px solid #d32f2f;font-size:1.1em;color:#d32f2f;font-style:italic;box-shadow:0 2px 8px #d32f2f22;">"La realidad a un click de distancia"</div>\n</div>\n\n<!-- PORTADA INSTITUCIONAL -->\n<img src="https://image.jimcdn.com/app/cms/image/transf/dimension=1280x10000:format=png/path/sff057b9e4174239e/image/i5c074e63e081578a/version/1752065836/image.png" alt="Portada institucional ZNSF" style="width:100%;max-width:900px;border-radius:16px;margin:24px auto 18px auto;display:block;box-shadow:0 4px 24px #0001;">\n\n<!-- PRESENTACION Y BLOQUE DESTACADO -->\n<div style="max-width:800px;margin:0 auto 18px auto;">\n  <p style="font-size:1.15em;line-height:1.6;">Desde el corazón del norte bonaerense nace <strong>ZNSF Noticias</strong>, un nuevo medio digital local pensado por y para los vecinos de San Fernando. Nuestro objetivo es claro: <em>informar, visibilizar, conectar y acompañar</em> cada historia, cada lucha, cada logro y cada rincón del municipio.</p>\n  <blockquote style="border-left:5px solid #d32f2f;padding-left:16px;color:#444;background:#f9f9f9;border-radius:8px;font-size:1.1em;margin:18px 0;box-shadow:0 2px 8px #d32f2f11;">\n    <em>"Somos un medio independiente, local y con identidad sanfernandina. Queremos ser el espacio donde tu voz se escuche."</em>\n  </blockquote>\n</div>\n\n<!-- BLOQUE: ¿QUÉ ES ZNSF NOTICIAS? -->\n<div style="display:flex;align-items:center;gap:18px;max-width:900px;margin:0 auto 24px auto;background:#f7f7f7;border-radius:12px;padding:18px 18px 12px 18px;box-shadow:0 2px 12px #d32f2f11;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i8269b5a654573c87/version/1752066756/image.png" alt="Logo simple ZNSF" style="width:80px;min-width:60px;max-width:20vw;">\n  <div style="flex:1;">\n    <h3 style="color:#d32f2f;margin:0 0 6px 0;">¿Qué hace ZNSF Noticias?</h3>\n    <ul style="margin:0 0 0 18px;padding:0;font-size:1.08em;line-height:1.5;color:#333;">\n      <li>Cubre <strong>noticias barriales</strong> y temas que afectan a los vecinos.</li>\n      <li>Hace <strong>recorridas</strong> por calles, plazas y zonas olvidadas.</li>\n      <li>Brinda <strong>alertas locales</strong> por WhatsApp.</li>\n      <li>Promueve la <strong>participación comunitaria</strong> y recibe contenido de los vecinos.</li>\n      <li>Da espacio a <strong>voceros barriales, jóvenes, comerciantes y organizaciones</strong>.</li>\n    </ul>\n  </div>\n</div>\n\n<!-- BLOQUE SANFI MASCOTA -->\n<div style="background:linear-gradient(90deg,#f7f7f7 60%,#e3f2fd 100%);border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;display:flex;align-items:center;gap:18px;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi la mascota de ZNSF" style="width:120px;max-width:30vw;">\n  <div style="flex:1;">\n    <h3 style="color:#d32f2f;margin:0 0 6px 0;">Conocé a Sanfi: nuestra mascota vecinal</h3>\n    <p style="margin:0;font-size:1.08em;">Inspirado en el símbolo del municipio y acompañado de un mate, <strong>Sanfi</strong> es nuestra mascota oficial. Representa la identidad barrial, la calidez vecinal y la energía positiva con la que encaramos este nuevo proyecto. ¡Lo vas a ver acompañando muchas de nuestras publicaciones!</p>\n  </div>\n</div>\n\n<!-- LLAMADO A PARTICIPACION Y BOTONES -->\n<div style="background:#fff3f2;border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;">\n  <h3 style="color:#d32f2f;">📝 ¿Sos vecino de San Fernando?</h3>\n  <p style="font-size:1.08em;">¿Tenés un reclamo, denuncia o historia para contar? ¿Querés que nuestras cámaras cubran un evento en tu barrio? ¿Tenés un comercio o emprendimiento y querés publicitar en nuestra sección de <strong>Clasificados</strong>?</p>\n  <div style="display:flex;flex-wrap:wrap;gap:12px;margin:12px 0 0 0;">\n    <a href="https://wa.me/5491137910547?text=Hola%20ZNSF%20Noticias%2C%20quiero%20enviar%20una%20noticia%20o%20consulta%20(desde%20publicar%20noticia%20web)" target="_blank" style="display:flex;align-items:center;gap:8px;background:#25d366;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #25d36633;transition:transform .1s;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i54f0f9e8bb7b09aa/version/1752083005/image.png" alt="WhatsApp" style="width:28px;">\n      Enviar WhatsApp\n    </a>\n    <a href="https://whatsapp.com/channel/0029Vb70uu90G0XdCw51eg0u" target="_blank" style="display:flex;align-items:center;gap:8px;background:#d32f2f;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #d32f2f33;transition:transform .1s;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i3fcaf367916af1a8/version/1752084059/image.png" alt="Canal WhatsApp" style="width:28px;">\n      Canal oficial\n    </a>\n    <a href="https://chat.whatsapp.com/EjvvlEb48y641BeACmlLlJ" target="_blank" style="display:flex;align-items:center;gap:8px;background:#222;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #2222;transition:transform .1s;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i94e3b69c51d5d643/version/1752084071/image.png" alt="Grupo Vecinos" style="width:28px;">\n      Grupo de vecinos\n    </a>\n    <span style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;font-size:1.08em;border:1.5px solid #d32f2f;user-select:all;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i9267260f4dd5540d/version/1752084082/image.png" alt="Gmail" style="width:24px;">\n      znsfnoticias@gmail.com\n    </span>\n  </div>\n</div>\n\n<!-- BLOQUE: SUMATE AL STAFF -->\n<div style="background:linear-gradient(90deg,#fff3f2 60%,#f7f7f7 100%);border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;display:flex;align-items:center;gap:18px;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo extendido ZNSF" style="width:90px;max-width:20vw;">\n  <div style="flex:1;">\n    <h3 style="color:#d32f2f;margin:0 0 6px 0;">¿Querés sumarte al staff?</h3>\n    <p style="margin:0;font-size:1.08em;">Buscamos colaboradores, cronistas, fotógrafos, editores y vecinos con ganas de aportar a la comunidad. ¡Sumate y hacé crecer el periodismo local!</p>\n    <a href="https://wa.me/5491137910547?text=Hola%20ZNSF%20Noticias%2C%20quiero%20sumarme%20al%20staff%20(desde%20publicar%20noticia%20web)" style="display:inline-block;margin-top:8px;background:#d32f2f;color:#fff;font-weight:bold;padding:8px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #d32f2f33;">Postularme por WhatsApp</a>\n    <span style="display:inline-block;margin-top:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:8px 18px;border-radius:8px;font-size:1.08em;border:1.5px solid #d32f2f;user-select:all;">znsfnoticias@gmail.com</span>\n  </div>\n</div>\n\n<!-- GALERÍA VISUAL DE SAN FERNANDO -->\n<h3 style="color:#d32f2f;text-align:center;margin-top:32px;">🚗 Nuestra ciudad, nuestro orgullo</h3>\n<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:18px;justify-content:center;margin-bottom:18px;max-width:900px;margin-left:auto;margin-right:auto;">\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i66f5872804799049/version/1752067632/image.png" alt="Costanera de San Fernando con Sanfi" style="width:100%;height:100%;object-fit:cover;display:block;transition:transform .3s;cursor:pointer;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Costanera y Sanfi</span>\n  </div>\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/if50361bf0e3a87ff/version/1752086858/image.jpg" alt="Avenida Avellaneda" style="width:100%;height:100%;object-fit:cover;display:block;transition:transform .3s;cursor:pointer;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Av. Avellaneda</span>\n  </div>\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i5800fb7c5f350890/version/1752086872/image.jpg" alt="Cartel San Fernando costanera" style="width:100%;height:100%;object-fit:cover;display:block;transition:transform .3s;cursor:pointer;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Cartel Costanera</span>\n  </div>\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/idfd1e2cee14f7ae6/version/1752086884/image.jpg" alt="Quinta Ombú fuente y estatua" style="width:100%;height:100%;object-fit:cover;display:block;transition:transform .3s;cursor:pointer;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Quinta Ombú</span>\n  </div>\n</div>\n\n<!-- CARRUSEL DE IMÁGENES AUTOMÁTICO -->\n<h3 style="color:#d32f2f;text-align:center;">📸 Momentos y paisajes de San Fernando</h3>\n<div id="carrusel-znsf" style="max-width:900px;margin:0 auto 18px auto;overflow:hidden;position:relative;">\n  <div id="carrusel-inner" style="display:flex;transition:transform .7s cubic-bezier(.7,0,.3,1);gap:18px;height:220px;">\n    <img src="https://www.sanfernando.gob.ar/images/principales/1440x810_DSC4149---copia.JPG" alt="Costanera oficial" style="width:320px;height:210px;object-fit:cover;border-radius:10px;box-shadow:0 2px 8px #0002;">\n    <img src="https://infocielo.com/wp-content/uploads/2024/12/20200705120036_7-plaza-mitre.jpeg" alt="Plaza Mitre" style="width:320px;height:210px;object-fit:cover;border-radius:10px;box-shadow:0 2px 8px #0002;">\n    <img src="https://infocielo.com/wp-content/uploads/2024/12/20200705115817_1-calle-constitucion.jpeg" alt="Calle Constitución" style="width:320px;height:210px;object-fit:cover;border-radius:10px;box-shadow:0 2px 8px #0002;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i226f2a2636d98ba3/version/1752086916/image.jpg" alt="Estación Virreyes" style="width:320px;height:210px;object-fit:cover;border-radius:10px;box-shadow:0 2px 8px #0002;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i1df1a35908e86dc8/version/1752086928/image.jpg" alt="Castillo estación San Fernando" style="width:320px;height:210px;object-fit:cover;border-radius:10px;box-shadow:0 2px 8px #0002;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i55f25b1b38f652c1/version/1752086939/image.jpg" alt="Parroquia Aránzazu" style="width:320px;height:210px;object-fit:cover;border-radius:10px;box-shadow:0 2px 8px #0002;">\n  </div>\n</div>\n<script>\nconst carrusel=document.getElementById('carrusel-inner');\nlet idx=0;\nconst total=6; // cantidad de imágenes\nfunction showCarrusel(){\n  if(carrusel){\n    carrusel.style.transform=`translateX(-${idx*338}px)`;\n  }\n}\nsetInterval(()=>{\n  idx=(idx+1)%total;\n  showCarrusel();\n},3000);\nshowCarrusel();\n</script>\n\n<!-- BLOQUE REDES SOCIALES Y CONTACTO -->\n<div style="max-width:900px;margin:0 auto 24px auto;background:#f7f7f7;border-radius:14px;padding:18px 18px 12px 18px;box-shadow:0 2px 12px #d32f2f11;">\n  <h3 style="color:#d32f2f;margin-bottom:10px;">Seguinos y participá en nuestras redes</h3>\n  <div style="display:flex;flex-wrap:wrap;gap:16px;align-items:center;justify-content:center;">\n    <a href="https://www.instagram.com/znsfnoticias" target="_blank" title="Instagram" style="display:flex;align-items:center;gap:8px;text-decoration:none;color:#222;font-weight:bold;font-size:1.08em;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/id31bfdb8887a4101/version/1752082976/image.png" alt="Instagram" style="width:32px;">Instagram\n    </a>\n    <a href="https://www.facebook.com/znsfnoticias" target="_blank" title="Facebook" style="display:flex;align-items:center;gap:8px;text-decoration:none;color:#222;font-weight:bold;font-size:1.08em;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i924b6a16ba5143d0/version/1752082966/image.png" alt="Facebook" style="width:32px;">Facebook\n    </a>\n    <a href="https://x.com/znsfnoticias" target="_blank" title="Twitter/X" style="display:flex;align-items:center;gap:8px;text-decoration:none;color:#222;font-weight:bold;font-size:1.08em;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/idd2b980f4adc5de5/version/1752083026/image.png" alt="Twitter X" style="width:32px;">Twitter/X\n    </a>\n    <a href="https://www.tiktok.com/@znsfnoticias" target="_blank" title="TikTok" style="display:flex;align-items:center;gap:8px;text-decoration:none;color:#222;font-weight:bold;font-size:1.08em;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/iafacb98ca891b2da/version/1752082994/image.png" alt="TikTok" style="width:32px;">TikTok\n    </a>\n    <a href="https://www.youtube.com/@ZNSFNoticias" target="_blank" title="YouTube" style="display:flex;align-items:center;gap:8px;text-decoration:none;color:#222;font-weight:bold;font-size:1.08em;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i28358835707a13d2/version/1752082985/image.png" alt="YouTube" style="width:32px;">YouTube\n    </a>\n    <a href="https://znsfnoticias.jimdofree.com/" target="_blank" title="Web principal" style="display:flex;align-items:center;gap:8px;text-decoration:none;color:#222;font-weight:bold;font-size:1.08em;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i28358835707a13d2/version/1752082985/image.png" alt="Web" style="width:32px;">Web principal\n    </a>\n  </div>\n</div>\n\n<!-- FOOTER INSTITUCIONAL -->\n<hr style="margin:32px 0 12px 0;border:0;border-top:2px solid #d32f2f33;">\n<div style="text-align:center;font-size:15px;color:#555;max-width:900px;margin:0 auto 18px auto;">\n  <strong>ZNSF Noticias</strong> • Medio Digital de San Fernando<br>\n  <span style="color:#d32f2f;">🌍</span> <a href="https://znsfnoticias.jimdofree.com/" target="_blank" style="color:#d32f2f;font-weight:bold;">znsfnoticias.jimdofree.com</a>  |\n  <span style="color:#25d366;">📢</span> <a href="https://whatsapp.com/channel/0029Vb70uu90G0XdCw51eg0u" target="_blank" style="color:#25d366;font-weight:bold;">Canal en WhatsApp</a>  |\n  <span style="color:#222;">👥</span> <a href="https://chat.whatsapp.com/EjvvlEb48y641BeACmlLlJ" target="_blank" style="color:#222;font-weight:bold;">Grupo Vecinal</a><br>\n  Seguinos en redes: <span style="color:#d32f2f;">@znsfnoticias</span>\n</div>\n\n<!-- MICROANIMACION: EFECTO DE ENTRADA PARA EL BANNER SUPERIOR -->\n<script>\n  window.addEventListener('DOMContentLoaded',()=>{\n    const banner=document.querySelector('div[style*="linear-gradient(90deg, #d32f2f"]');\n    if(banner){\n      banner.style.transform='translateY(-60px)';\n      banner.style.opacity='0';\n      setTimeout(()=>{\n        banner.style.transition='all .7s cubic-bezier(.7,0,.3,1)';\n        banner.style.transform='translateY(0)';\n        banner.style.opacity='1';\n      },200);\n    }\n  });\n</script>$$, '2025-07-09', 'Institucional', 'https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i66f5872804799049/version/1752067632/image.png', NULL, '2025-07-09 14:03:52.793038+00', 72, 461, 20, 2, 2, '2025-07-09 14:03:52.793038+00', NULL),
(10, '🦮 ¡Ayudemos a encontrar a Clemente!', $$<!-- 27 345  28/357BANNER SUPERIOR CON LOGO Y FONDO INSTITUCIONAL -->\n<div style="background: linear-gradient(90deg, #d32f2f 60%, #f9f9f9 100%); padding: 24px 0 12px 0; border-radius: 0 0 32px 32px; box-shadow: 0 4px 24px #0002; position:relative; overflow:hidden;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF Noticias extendido" style="width:340px;max-width:90vw;display:block;margin:0 auto 8px auto;filter:drop-shadow(0 2px 8px #0005);position:relative;z-index:2;">\n  <div style="position:absolute;right:24px;bottom:-10px;z-index:2;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi mascota" style="width:90px;max-width:20vw;">\n  </div>\n</div>\n\n<!-- TITULO Y SLOGAN -->\n<div style="text-align:center;margin-top:18px;">\n  <h1 style="color:#d32f2f;font-size:2.2em;margin-bottom:0;">🦮 Mascotas Perdidas: ¡Ayudemos a encontrar a Clemente!</h1>\n  <h2 style="color:#222;font-size:1.3em;font-style:italic;margin-top:0;">Vecinos de Virreyes buscan a su gatito perdido desde Gandolfo al 2800</h2>\n  <p style="color:#555;font-size:1.1em;margin:0 0 8px 0;"><strong>Virreyes, Buenos Aires – Sábado 12 de julio de 2025</strong></p>\n  <div style="display:inline-block;background:#fff3f2;border-radius:8px;padding:6px 18px;margin-bottom:8px;border:1.5px solid #d32f2f;font-size:1.1em;color:#d32f2f;font-style:italic;box-shadow:0 2px 8px #d32f2f22;">"Ellos también extrañan a sus hogares y familias"</div>\n</div>\n\n\n<a href="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/id945d409461e6781/version/1752339112/image.png" target="_blank">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/id945d409461e6781/version/1752339112/image.png" alt="Sanfi Dice" style="width:100%;max-width:900px;border-radius:16px;margin:24px auto 18px auto;display:block;box-shadow:0 4px 24px #0001;cursor:pointer;">\n</a>\n\n<!-- PORTADA INSTITUCIONAL -->\n<div style="position:relative;max-width:900px;margin:24px auto 18px auto;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i2b4644cca15bbd5c/version/1752315118/image.jpg" alt="Cartel de búsqueda de Clemente" style="width:100%;border-radius:16px;box-shadow:0 4px 24px #0001;display:block;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF marca de agua" style="position:absolute;bottom:12px;right:12px;width:80px;opacity:0.7;pointer-events:none;">\n  <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi marca de agua" style="position:absolute;top:12px;left:12px;width:60px;opacity:0.7;pointer-events:none;">\n  <div style="position:absolute;bottom:24px;left:24px;background:#fff3f2cc;padding:8px 18px;border-radius:10px;color:#d32f2f;font-weight:bold;font-size:1.15em;box-shadow:0 2px 8px #d32f2f22;">Ayudemos a encontrar a Clemente</div>\n</div>\n\n<!-- PRESENTACION Y BLOQUE DESTACADO -->\n<div style="max-width:800px;margin:0 auto 18px auto;">\n  <p style="font-size:1.25em;line-height:1.7;">\n    Cada día, incontables mascotas buscan volver con sus familias. <strong>Clemente</strong> es uno de ellos: se perdió el <strong>1 de julio</strong> en Gandolfo al 2800, Virreyes. Su familia y vecinos no han dejado de buscarlo ni un solo día.<br><br>\n    <span style="background:#fff3f2;padding:2px 8px;border-radius:6px;color:#d32f2f;font-weight:bold;">Responde al nombre de Clemente y tiene un bigote marrón del lado izquierdo de la nariz.</span><br><br>\n    Al <strong>12 de julio</strong>, Clemente lleva <span style="color:#d32f2f;font-weight:bold;">11 días lejos de su familia</span>. Cada día que pasa, la esperanza y el amor de quienes lo esperan crecen.<br><br>\n    Las mascotas perdidas suelen recorrer grandes distancias y pueden aparecer en barrios cercanos. Compartir su foto y datos puede marcar la diferencia.<br><br>\n    Si lo viste, si tienes información, <strong>no dudes en avisar</strong>. Tu ayuda puede reunir a Clemente con su familia.<br><br>\n    <span style="color:#1976d2;font-weight:bold;">¿Sabías que más del 60% de los animales perdidos logran volver a casa gracias a la colaboración vecinal y la difusión en redes?</span>\n  </p>\n</div>\n\n<!-- BLOQUE: UBICACIÓN Y MAPA -->\n<div style="max-width:900px;margin:0 auto 24px auto;background:#e3f2fd;border-radius:14px;box-shadow:0 2px 12px #1976d211;padding:18px 18px 12px 18px;">\n  <h3 style="color:#1976d2;margin:0 0 6px 0;font-size:1.18em;">¿Dónde se perdió Clemente?</h3>\n  <p style="margin:0;font-size:1.12em;">Zona: Gandolfo al 2800, intersección con Fray Justo Sta. María de Oro, Virreyes.>\n    <a href="https://www.google.com/maps/place/Gandolfo+2800,+B1645CXZ+Virreyes,+Provincia+de+Buenos+Aires/@-34.4571733,-58.5614346,3a,75y,241.21h,90t/data=!3m7!1e1!3m5!1s010TfJo0HGyQOjoO25yb-w!2e0!6shttps:%2F%2Fstreetviewpixels-pa.googleapis.com%2Fv1%2Fthumbnail%3Fcb_client%3Dmaps_sv.tactile%26w%3D900%26h%3D600%26pitch%3D0%26panoid%3D010TfJo0HGyQOjoO25yb-w%26yaw%3D241.2101!7i16384!8i8192!4m13!1m7!3m6!1s0x95bca55a4ecf6667:0x4ff71418aa6f5dc3!2sGandolfo+2800,+B1645CXZ+Virreyes,+Provincia+de+Buenos+Aires!3b1!8m2!3d-34.4571948!4d-58.5614617!3m4!1s0x95bca55a4ecf6667:0x4ff71418aa6f5dc3!8m2!3d-34.4571948!4d-58.5614617?entry=ttu&g_ep=EgoyMDI1MDcwOS4wIKXMDSoASAFQAw%3D%3D" target="_blank" style="color:#1976d2;font-weight:bold;text-decoration:underline;">Ver ubicación en Google Maps</a>\n  </p>\n</div>\n\n<!-- BLOQUE GALERÍA DE IMÁGENES DE CLEMENTE -->\n<h3 style="color:#d32f2f;text-align:center;margin-top:32px;">📸 Imágenes de Clemente</h3>\n<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:18px;justify-content:center;margin-bottom:18px;max-width:900px;margin-left:auto;margin-right:auto;">\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <a href="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/iacf6e552a8828305/version/1752315285/image.png" target="_blank" style="display:block;width:100%;height:100%;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/iacf6e552a8828305/version/1752315285/image.png" alt="Clemente en la cama" style="width:100%;height:100%;object-fit:cover;display:block;">\n    </a>\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF marca de agua" style="position:absolute;bottom:10px;right:10px;width:50px;opacity:0.7;pointer-events:none;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi marca de agua" style="position:absolute;top:10px;left:10px;width:36px;opacity:0.7;pointer-events:none;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Clemente en casa</span>\n  </div>\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <a href="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i9b5b0c03883d06e5/version/1752315297/image.png" target="_blank" style="display:block;width:100%;height:100%;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i9b5b0c03883d06e5/version/1752315297/image.png" alt="Clemente primer plano" style="width:100%;height:100%;object-fit:cover;display:block;">\n    </a>\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF marca de agua" style="position:absolute;bottom:10px;right:10px;width:50px;opacity:0.7;pointer-events:none;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi marca de agua" style="position:absolute;top:10px;left:10px;width:36px;opacity:0.7;pointer-events:none;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Clemente en la ventana</span>\n  </div>\n  <div style="overflow:hidden;border-radius:12px;box-shadow:0 2px 8px #0002;position:relative;background:#fff;aspect-ratio:4/3;display:flex;align-items:flex-end;">\n    <a href="https://image.jimcdn.com/app/cms/image/transf/dimension=1280x10000:format=png/path/sff057b9e4174239e/image/ic979187871dbebed/version/1752315310/image.png" target="_blank" style="display:block;width:100%;height:100%;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/dimension=1280x10000:format=png/path/sff057b9e4174239e/image/ic979187871dbebed/version/1752315310/image.png" alt="Esquina Gandolfo al 2800" style="width:100%;height:100%;object-fit:cover;display:block;">\n    </a>\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i402e4c896fc5fcd0/version/1752066539/image.png" alt="Logo ZNSF marca de agua" style="position:absolute;bottom:10px;right:10px;width:50px;opacity:0.7;pointer-events:none;">\n    <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i4c7cac3ca0b2111b/version/1752065884/image.png" alt="Sanfi marca de agua" style="position:absolute;top:10px;left:10px;width:36px;opacity:0.7;pointer-events:none;">\n    <span style="position:absolute;bottom:10px;left:10px;background:#fff9;padding:4px 12px;border-radius:8px;font-size:1em;color:#d32f2f;font-weight:bold;box-shadow:0 2px 8px #0001;">Zona Gandolfo al 2800</span>\n  </div>\n</div>\n\n<!-- BLOQUE MASCOTAS PERDIDAS Y LLAMADO A LA ACCIÓN -->\n<div style="background:#fff3f2;border-radius:14px;box-shadow:0 2px 12px #d32f2f11;padding:18px 18px 12px 18px;max-width:900px;margin:0 auto 24px auto;">\n  <h3 style="color:#d32f2f;">¿Perdiste a tu mascota?</h3>\n  <p style="font-size:1.15em;">En ZNSF Noticias ayudamos a difundir casos de mascotas perdidas. Si tienes información sobre Clemente o quieres publicar sobre otra mascota, <strong>envianos fotos y datos</strong> para que podamos ayudar.<br>\n    <span style="color:#d32f2f;font-weight:bold;">Ellos también extrañan a sus hogares y familias.</span>\n  </p>\n  <a href="https://wa.me/5491137910547?text=Hola.%20Informacion%20sobre%20Mascotas%20perdidas" target="_blank" style="display:inline-block;margin-top:8px;background:#25d366;color:#fff;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;box-shadow:0 2px 8px #25d36633;">Enviar información por WhatsApp</a>\n</div>\n\n<!-- BLOQUE REDES SOCIALES Y CONTACTO -->\n<div style="max-width:900px;margin:0 auto 24px auto;background:#f7f7f7;border-radius:14px;padding:18px 18px 12px 18px;box-shadow:0 2px 12px #d32f2f11;">\n  <h3 style="color:#d32f2f;margin-bottom:10px;font-size:1.25em;">Seguinos y participá en nuestras redes</h3>\n  <div style="display:flex;flex-wrap:wrap;gap:16px;align-items:center;justify-content:center;">\n    <a href="https://www.instagram.com/znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/id31bfdb8887a4101/version/1752082976/image.png" alt="Instagram" style="width:24px;"> Instagram\n    </a>\n    <a href="https://www.youtube.com/@ZNSFNoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i2c42051c382a77df/version/1752083038/image.png" alt="YouTube" style="width:24px;"> YouTube\n    </a>\n    <a href="https://x.com/znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/idd2b980f4adc5de5/version/1752083026/image.png" alt="Twitter/X" style="width:24px;"> Twitter/X\n    </a>\n    <a href="https://www.tiktok.com/@znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/iafacb98ca891b2da/version/1752082994/image.png" alt="TikTok" style="width:24px;"> TikTok\n    </a>\n    <a href="https://www.facebook.com/znsfnoticias" target="_blank" style="display:flex;align-items:center;gap:8px;background:#fff;color:#d32f2f;font-weight:bold;padding:10px 18px;border-radius:8px;text-decoration:none;font-size:1.08em;border:1.5px solid #d32f2f;">\n      <img src="https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i924b6a16ba5143d0/version/1752082966/image.png" alt="Facebook" style="width:24px;"> Facebook\n    </a>\n  </div>\n</div>\n\n<!-- FOOTER INSTITUCIONAL -->\n<hr style="margin:32px 0 12px 0;border:0;border-top:2px solid #d32f2f33;">\n<div style="text-align:center;font-size:17px;color:#555;max-width:900px;margin:0 auto 18px auto;">\n  <strong>ZNSF Noticias</strong> • Medio Digital de Zona Norte<br>\n  <span style="color:#d32f2f;">🌍</span> <a href="https://znsfnoticias.jimdofree.com/" target="_blank" style="color:#d32f2f;font-weight:bold;">znsfnoticias.jimdofree.com</a>  |\n  <span style="color:#25d366;">📢</span> <a href="https://whatsapp.com/channel/0029Vb70uu90G0XdCw51eg0u" target="_blank" style="color:#25d366;font-weight:bold;">Canal en WhatsApp</a>  |\n  <span style="color:#222;">👥</span> <a href="https://chat.whatsapp.com/EjvvlEb48y641BeACmlLlJ" target="_blank" style="color:#222;font-weight:bold;">Grupo Vecinal</a><br>\n  Seguinos en redes: <span style="color:#d32f2f;">@znsfnoticias</span>\n</div>\n\n<!-- MICROANIMACION: EFECTO DE ENTRADA PARA EL BANNER SUPERIOR -->\n<script>\n  window.addEventListener('DOMContentLoaded',()=>{\n    const banner=document.querySelector('div[style*="linear-gradient"]');\n    if(banner){\n      banner.style.transform='translateY(-40px)';\n      banner.style.opacity='0';\n      setTimeout(()=>{\n        banner.style.transition='all .7s cubic-bezier(.7,0,.3,1)';\n        banner.style.transform='translateY(0)';\n        banner.style.opacity='1';\n      },200);\n    }\n  });\n</script>$$, '2025-07-12', 'Mascotas Perdidas', 'https://image.jimcdn.com/app/cms/image/transf/none/path/sff057b9e4174239e/image/i9b5b0c03883d06e5/version/1752315297/image.png', NULL, '2025-07-12 10:31:48.290792+00', 29, 368, 22, 2, 2, '2025-07-12 10:31:48.290792+00', NULL);